mapper.select:
SELECT A.구직번호 jobNo, A.참여자 participantName, A.생년월일 birthDate, A.성별 gender, A.지점 branch, A.전담자_계정 counselorAccount, M.이름 counselorName, A.진행단계 progressStage, CONVERT(varchar, A.등록일, 23) participantRegDate, A.마감 closed FROM J_참여자관리 A LEFT JOIN J_참여자관리_로그인정보 M ON A.전담자_계정 = M.아이디 WHERE 1=1
AND CAST(A.구직번호 AS NVARCHAR) LIKE #{searchJobNo} + '%'
AND A.참여자 LIKE '%' + #{searchName} + '%'
AND A.지점 = #{searchBranch}
AND A.전담자_계정 = #{searchCounselor}
AND A.진행단계 = #{searchStatus}
AND A.등록일 >= CAST(#{searchStartDate} AS date)
AND A.등록일 < DATEADD(day, 1, CAST(#{searchEndDate} AS date))
AND A.마감 = #{searchClosed}
ORDER BY A.구직번호 DESC
